# https://github.com/jreusser/RosalindSolutions
from library import DNASequence
class CountingDnaNucleotides:
    def __init__(self, instring: str):
        self.instring = DNASequence(instring)

    def counter(self) -> str:
        return " ".join(str(self.instring.count(nuc)) for nuc in "ACGT")

if __name__ == "__main__":
    instring = ""
    counting_dna_nucleotides = CountingDnaNucleotides(instring)
    print(counting_dna_nucleotides.counter())